-- ============================================
-- Chapter 3: Intermediate SQL\n-- 03. Triggers\n-- 01. Introduction to Triggers\n-- ============================================\n-- TRIGGERS are automated actions that execute in response to database events\n\nUSE company;\n\n-- ============================================\n-- 1. CREATE TRIGGER: Basic Syntax\n-- ============================================\n-- Trigger that fires AFTER INSERT on employees\n\nCREATE TABLE IF NOT EXISTS employees (\n    emp_id INT PRIMARY KEY AUTO_INCREMENT,\n    first_name VARCHAR(50),\n    last_name VARCHAR(50),\n    salary DECIMAL(10,2),\n    department VARCHAR(50),\n    created_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Audit table to log changes\nCREATE TABLE IF NOT EXISTS employee_audit (\n    audit_id INT PRIMARY KEY AUTO_INCREMENT,\n    emp_id INT,\n    action VARCHAR(50),\n    action_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    details TEXT\n);\n\n-- AFTER INSERT Trigger\nDELIMITER $$\nCREATE TRIGGER employee_insert_trigger\nAFTER INSERT ON employees\nFOR EACH ROW\nBEGIN\n    INSERT INTO employee_audit (emp_id, action, details)\n    VALUES (NEW.emp_id, 'INSERT', CONCAT('New employee: ', NEW.first_name, ' ', NEW.last_name));\nEND$$\nDELIMITER ;\n\n-- ============================================\n-- 2. TEST THE TRIGGER\n-- ============================================\nINSERT INTO employees (first_name, last_name, salary, department)\nVALUES ('Alice', 'Smith', 90000, 'Sales');\n\n-- Check audit table\nSELECT * FROM employee_audit;\n\n-- ============================================\n-- 3. BEFORE TRIGGER\n-- ============================================\n-- Validate data before insert\n\nDELIMITER $$\nCREATE TRIGGER salary_validation_trigger\nBEFORE INSERT ON employees\nFOR EACH ROW\nBEGIN\n    IF NEW.salary < 0 THEN\n        SIGNAL SQLSTATE '45000'\n        SET MESSAGE_TEXT = 'Salary cannot be negative';\n    END IF;\nEND$$\nDELIMITER ;\n\n-- Test - this will fail\n-- INSERT INTO employees (first_name, last_name, salary, department)\n-- VALUES ('Bob', 'Johnson', -50000, 'IT');\n-- ERROR: Salary cannot be negative\n\n-- ============================================\n-- 4. AFTER UPDATE TRIGGER\n-- ============================================\nDELIMITER $$\nCREATE TRIGGER employee_update_trigger\nAFTER UPDATE ON employees\nFOR EACH ROW\nBEGIN\n    INSERT INTO employee_audit (emp_id, action, details)\n    VALUES (NEW.emp_id, 'UPDATE', \n            CONCAT('Updated - Old: ', OLD.salary, ', New: ', NEW.salary));\nEND$$\nDELIMITER ;\n\n-- Test update\nUPDATE employees SET salary = 95000 WHERE emp_id = 1;\n\nSELECT * FROM employee_audit;\n\n-- ============================================\n-- 5. AFTER DELETE TRIGGER\n-- ============================================\nDELIMITER $$\nCREATE TRIGGER employee_delete_trigger\nAFTER DELETE ON employees\nFOR EACH ROW\nBEGIN\n    INSERT INTO employee_audit (emp_id, action, details)\n    VALUES (OLD.emp_id, 'DELETE', CONCAT('Deleted: ', OLD.first_name, ' ', OLD.last_name));\nEND$$\nDELIMITER ;\n\n-- ============================================\n-- 6. VIEW EXISTING TRIGGERS\n-- ============================================\nSHOW TRIGGERS;\n\n-- Get detailed trigger info\nSELECT * FROM INFORMATION_SCHEMA.TRIGGERS\nWHERE TRIGGER_SCHEMA = 'company';\n\n-- ============================================\n-- 7. DROP TRIGGER\n-- ============================================\nDROP TRIGGER IF EXISTS employee_insert_trigger;\n\n-- ============================================\n-- 8. PRACTICAL EXAMPLES\n-- ============================================\n\n-- Example 1: Maintain summary table\nCREATE TABLE IF NOT EXISTS dept_employee_count (\n    department VARCHAR(50) PRIMARY KEY,\n    employee_count INT DEFAULT 0\n);\n\nDELIMITER $$\nCREATE TRIGGER update_dept_count_insert\nAFTER INSERT ON employees\nFOR EACH ROW\nBEGIN\n    UPDATE dept_employee_count \n    SET employee_count = employee_count + 1\n    WHERE department = NEW.department;\nEND$$\nDELIMITER ;\n\n-- Example 2: Prevent duplicate entries\nCREATE TABLE IF NOT EXISTS employee_codes (\n    emp_id INT,\n    employee_code VARCHAR(20) UNIQUE\n);\n\nDELIMITER $$\nCREATE TRIGGER prevent_duplicate_code\nBEFORE INSERT ON employee_codes\nFOR EACH ROW\nBEGIN\n    IF EXISTS (SELECT 1 FROM employee_codes WHERE employee_code = NEW.employee_code) THEN\n        SIGNAL SQLSTATE '45000'\n        SET MESSAGE_TEXT = 'Employee code already exists';\n    END IF;\nEND$$\nDELIMITER ;\n\n-- ============================================\n-- 9. TRIGGER WITH MULTIPLE STATEMENTS\n-- ============================================\nDELIMITER $$\nCREATE TRIGGER complex_trigger\nAFTER INSERT ON employees\nFOR EACH ROW\nBEGIN\n    -- Insert audit record\n    INSERT INTO employee_audit (emp_id, action, details)\n    VALUES (NEW.emp_id, 'INSERT', 'New employee added');\n    \n    -- Update department count\n    UPDATE dept_employee_count \n    SET employee_count = employee_count + 1\n    WHERE department = NEW.department;\n    \n    -- Send notification (simulated)\n    -- Actual implementation would call external system\nEND$$\nDELIMITER ;\n\n-- ============================================\n-- 10. TRIGGER TIMING AND EVENTS\n-- ============================================\n-- BEFORE INSERT: Validate before insert\n-- AFTER INSERT: Log after insert\n-- BEFORE UPDATE: Validate updates\n-- AFTER UPDATE: Log changes\n-- BEFORE DELETE: Prevent invalid deletes\n-- AFTER DELETE: Archive or notify\n\n-- ============================================\n-- 11. NEW AND OLD REFERENCES\n-- ============================================\n-- NEW: References new values (INSERT, UPDATE)\n-- OLD: References old values (UPDATE, DELETE)\n-- Both available in UPDATE triggers only\n\n-- ============================================\n-- 12. IMPORTANT CONSIDERATIONS\n-- ============================================\n-- - Triggers increase overhead\n-- - Debugging can be difficult\n-- - Keep logic simple and clear\n-- - Document trigger purposes\n-- - Avoid cascading triggers\n-- - Test thoroughly before production\n"